(() => {
    interface CircularDeep {
      deep1: {deep2: {deep3: {deep4?: CircularDeep}}};
    }
    return {build: () => createValidate<CircularDeep>(), buildErrors: () => noErrs(createGetValidationErrors<CircularDeep>())};
  })()

() => {
    const cd = RT.circular((self) =>
      RT.object({
        deep1: RT.object({
          deep2: RT.object({deep3: RT.object({deep4: RT.optional(self)})}),
        }),
      })
    );
    return createValidate(cd);
  }

(() => {
    interface CircularDeep {
      deep1: {deep2: {deep3: {deep4?: CircularDeep}}};
    }
    return {
      build: () => {
        const check = typia.createIs<CircularDeep>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<CircularDeep>();
        return (v) => val(v).success;
      },
    };
  })()

c(
    Type.Recursive((This) =>
      Type.Object({
        deep1: Type.Object({
          deep2: Type.Object({
            deep3: Type.Object({deep4: Type.Optional(This)}),
          }),
        }),
      })
    )
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.object({
      deep1: z.object({
        deep2: z.object({
          deep3: z.custom((v) => {
            if (typeof v !== 'object' || v === null) return false;
            const obj = v as Record<string, unknown>;
            if ('deep4' in obj) {
              // if deep4 is present it must be a valid T
              return schema.safeParse(obj.deep4).success;
            }
            return true; // empty object (no deep4)
          }),
        }),
      }),
    });
    return schema;
  }))
